import{_ as i,c as n,o as t,ae as o}from"./chunks/framework.B7Y1jjX-.js";const c=JSON.parse('{"title":"第一章 绪论","description":"","frontmatter":{},"headers":[],"relativePath":"notes/学习/408/数据结构/第一章 绪论.md","filePath":"notes/学习/408/数据结构/第一章 绪论.md"}'),r={name:"notes/学习/408/数据结构/第一章 绪论.md"};function s(g,l,a,e,u,_){return t(),n("div",null,[...l[0]||(l[0]=[o('<h1 id="第一章-绪论" tabindex="-1">第一章 绪论 <a class="header-anchor" href="#第一章-绪论" aria-label="Permalink to &quot;第一章 绪论&quot;">​</a></h1><h3 id="数据结构基本概念" tabindex="-1">数据结构基本概念 <a class="header-anchor" href="#数据结构基本概念" aria-label="Permalink to &quot;数据结构基本概念&quot;">​</a></h3><ul><li><strong>数据</strong>：是信息的载体，描述客观事物属性的数、字符等能被计算机识别和处理的符号集合</li><li><strong>数据元素</strong>：数据的基本单位，通常作为整体考虑，由若干数据项组成（是不可分割的最小单位）</li><li><strong>数据对象</strong>：具有相同性质的数据元素的集合</li><li><strong>数据类型</strong>：一个值的集合和在此集合上的一组操作 <ul><li><strong>原子类型</strong>：其值不可再分，如：int、bool</li><li><strong>结构类型</strong>：其值可以分为若干的成分数据类型，如：结构体</li><li><strong>抽象数据类型</strong>：ADT，使用数学化的语言定义数据的逻辑结构和运算，不定义实现（逻辑结构）</li></ul></li><li><strong>数据结构</strong>：互相存在关系的数据元素的集合 <ul><li><strong>逻辑结构</strong>：指数据结构间的逻辑结构，与数据的存储无关 <ul><li><strong>线性结构</strong>：数据元素间存在一对一的关系，存在唯一的前驱和后继 <ul><li>线性表</li><li>栈和队列</li><li>数组</li></ul></li><li><strong>非线性结构</strong>： <ul><li>集合：属于同一个集合，再无其他关系</li><li>树：数据元素间存在一对多的关系</li><li>网：数据元素间存在多对多的关系</li></ul></li></ul></li><li><strong>存储结构</strong>：又称物理结构，会影响数据的运算和存储空间的分配复杂度的不同 <ul><li><strong>顺序存储</strong>：逻辑上相邻的元素在物理上也连续存储 <ul><li>优点：能够实现顺序存储</li><li>缺点：只能使用连续的一块空间，存在外部碎片</li></ul></li><li><strong>链式存储</strong>：使用指针来链接各个原数 <ul><li>优点：不会出现碎片</li><li>缺点：占用额外的空间，只能顺序存储</li></ul></li><li><strong>索引存储</strong>：使用索引表 <ul><li>优点：检索速度快</li><li>缺点：占用额外的空间，需要额外的修改</li></ul></li><li><strong>散列存储</strong>：又称哈希存储 <ul><li>优点：检索、增加和删除的速度都很快</li><li>缺点：可能出现数据单元的冲突</li></ul></li></ul></li><li><strong>数据运算</strong>：包括定义和实现，定义针对逻辑结构，实现针对物理结构</li></ul></li></ul><h3 id="算法和评价" tabindex="-1">算法和评价 <a class="header-anchor" href="#算法和评价" aria-label="Permalink to &quot;算法和评价&quot;">​</a></h3><p><strong>算法</strong>：针对特定问题的求解的步骤的一种描述，是指令的有限序列，每个指令表示一个或者多个操作</p><ul><li><strong>算法特征</strong>： <ul><li>有穷性：必须在有限步数内执行完毕，且每步必须在有限的时间内完成</li><li>确定性：相同的输入必有相同的结果</li><li>可行性：每步均可以使用已经实现的基本运算执行有限次来实现</li><li>输入：有零个或者多个</li><li>输出：有一个或者多个</li></ul></li><li><strong>算法评价</strong>： <ul><li>正确性：正确的解决问题</li><li>可读性：具有良好的可读性</li><li>健壮性：输入非法数据时能够处理</li><li>高效率低存储：时间空间复杂度低</li></ul></li><li><strong>算法效率度量</strong>： <ul><li><strong>时间复杂度</strong>：一个语句的频度指在算法中重复执行的次数，使用T(n)=O(f(n))来描述，f(n)指随深层循环语句的执行次数（浅层循环和顺序执行的代码不做考虑），通常填入表达式中将系数改为“1”的最高阶项，通常指最坏情况下的 <ul><li>加法规则：O(f(n))+O(g(n))=O(max(f(n),g(n)))</li><li>乘法规则：O(f(n))×O(g(n))=O(f(n)×g(n))</li><li>常见复杂度：1&lt;log2n&lt;n&lt;nlog2n&lt;n^2&lt;n^3&lt;2^n&lt;n!&lt;n^n.</li></ul></li><li><strong>空间复杂度</strong>：S(n)=O(g(n))，一个程序运行的时候需要的空间包括程序本身和计算所需要的辅助空间，算法的原地工作指算法所需的辅助空间的大小为零O(1)</li></ul></li></ul>',6)])])}const f=i(r,[["render",s]]);export{c as __pageData,f as default};
